    code: 'public class TimedCache<K, V> {\n  private Map<K, V> cache = new HashMap<>();\n  private Map<K, Long> timestamps = new HashMap<>();\n  private long ttlMs;\n  public TimedCache(long ttlMs) {\n    this.ttlMs = ttlMs;\n  }\n  public void put(K key, V value) {\n    cache.put(key, value);\n    timestamps.put(key, System.currentTimeMillis());\n  }\n  public V get(K key) {\n    if (timestamps.containsKey(key) && System.currentTimeMillis() - timestamps.get(key) > ttlMs) {\n      cache.remove(key);\n      timestamps.remove(key);\n      return null;\n    }\n    return cache.get(key);\n  }\n}',
